import{_ as t,o as e,c as o,Q as s}from"./chunks/framework.32dba02b.js";const n="/devops-doc/assets/Git工作区域.7f6dadd0.png",r="/devops-doc/assets/Git文件状态.62a7ed0d.png",_=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Tools/VersionManagement/concept.md","filePath":"Tools/VersionManagement/concept.md","lastUpdated":1697596099000}'),l={name:"Tools/VersionManagement/concept.md"},a=s('<h2 id="工作区域" tabindex="-1">工作区域 <a class="header-anchor" href="#工作区域" aria-label="Permalink to &quot;工作区域&quot;">​</a></h2><p><img src="'+n+'" alt="Git工作区域"></p><ul><li><p><strong>Workspace</strong> 工作区：存放项目代码的目录。</p></li><li><p><strong>Index/Stage</strong> 暂存区：保存下次提交的文件列表信息，本质上是一个叫 index 的文件，一般在 Git 仓库目录中，通常多数说法还是叫暂存区域。</p></li><li><p><strong>Repository</strong> 仓库区（或版本库）：存放数据的位置，存放所有提交到仓库区的版本数据。其中 HEAD 指向最新放入仓库的版本。</p></li><li><p><strong>Remote</strong> 远程仓库：托管代码的服务器。</p></li></ul><h2 id="文件状态" tabindex="-1">文件状态 <a class="header-anchor" href="#文件状态" aria-label="Permalink to &quot;文件状态&quot;">​</a></h2><p><img src="'+r+'" alt="Git文件状态"></p><ul><li><p><strong>Untracked</strong> 未跟踪：文件不参与版本控制。</p></li><li><p><strong>Unmodify</strong> 未修改：文件为最新状态。</p></li><li><p><strong>Modified</strong> 已修改：文件已修改。</p></li><li><p><strong>Staged</strong> 暂存状态：文件修改已暂时记录。</p></li></ul><h2 id="版本控制系统-version-control-system-vcs" tabindex="-1">版本控制系统（Version Control System，VCS） <a class="header-anchor" href="#版本控制系统-version-control-system-vcs" aria-label="Permalink to &quot;版本控制系统（Version Control System，VCS）&quot;">​</a></h2><p>帮助软件团队的开发人员协同工作，并存档他们工作的完整历史记录。</p><table><thead><tr><th style="text-align:center;">代</th><th style="text-align:center;">网络</th><th style="text-align:center;">操作</th><th style="text-align:center;">并发性</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>第一代（本地版本控制系统）</strong></td><td style="text-align:center;">无</td><td style="text-align:center;">仅一个文件</td><td style="text-align:center;">锁定的</td></tr><tr><td style="text-align:center;"><strong>第二代（集中化版本控制系统）</strong></td><td style="text-align:center;">集中式</td><td style="text-align:center;">多文件</td><td style="text-align:center;">提交之前合并</td></tr><tr><td style="text-align:center;"><strong>第三代（分布式版本控制系统）</strong></td><td style="text-align:center;">分布式</td><td style="text-align:center;">变更的集合</td><td style="text-align:center;">合并之前提交</td></tr></tbody></table><h3 id="本地版本控制系统-local-version-control-system-lvcs" tabindex="-1">本地版本控制系统（Local Version Control System，LVCS） <a class="header-anchor" href="#本地版本控制系统-local-version-control-system-lvcs" aria-label="Permalink to &quot;本地版本控制系统（Local Version Control System，LVCS）&quot;">​</a></h3><p>通过加锁将并发执行转换成顺序执行。一次只能有一个人处理文件。</p><blockquote><p><strong>悲观锁</strong></p><ul><li><p>每次获取数据的时候，都会担心数据被修改，所以每次获取数据的时候都会进行加锁，确保在自己使用的过程中数据不会被别人修改，使用完成后进行数据解锁。</p></li><li><p>由于数据进行加锁，期间对该数据进行读写的其他线程都会进行等待。</p></li></ul></blockquote><h3 id="集中化版本控制系统-centralized-version-control-systems-cvcs" tabindex="-1">集中化版本控制系统（Centralized Version Control Systems，CVCS） <a class="header-anchor" href="#集中化版本控制系统-centralized-version-control-systems-cvcs" aria-label="Permalink to &quot;集中化版本控制系统（Centralized Version Control Systems，CVCS）&quot;">​</a></h3><p>对同步修改更加宽容，但有一个明显的限制，用户必须在允许提交之前将当前修订合并到他们的工作中。</p><blockquote><p><strong>乐观锁</strong></p><ul><li><p>每次获取数据的时候，都不会担心数据被修改，所以每次获取数据的时候都不会进行加锁，但是在更新数据的时候需要判断该数据是否被别人修改过。</p></li><li><p>如果数据被其他线程修改，则不进行数据更新，如果数据没有被其他线程修改，则进行数据更新。由于数据没有进行加锁，期间该数据可以被其他线程进行读写操作。</p></li></ul></blockquote><h3 id="分布式版本控制系统-distributed-version-control-systems-dvcs" tabindex="-1">分布式版本控制系统（Distributed Version Control Systems，DVCS） <a class="header-anchor" href="#分布式版本控制系统-distributed-version-control-systems-dvcs" aria-label="Permalink to &quot;分布式版本控制系统（Distributed Version Control Systems，DVCS）&quot;">​</a></h3><p>允许合并和提交分开。在每个使用者电脑上就有一个完整的数据仓库，没有网络依然可以使用。</p>',17),i=[a];function c(d,p,g,h,m,y){return e(),o("div",null,i)}const x=t(l,[["render",c]]);export{_ as __pageData,x as default};
